"""
MABE Bootstrap: Module 4a — Coordination-Optics Bridge

Run: python3 bootstrap_optical_m4a_bridge.py

Prerequisites:
  - optical/ M1-M9 foundation (from bootstrap_optical_foundation.py)
  - core/scorer_frozen.py (existing binding engine)
  - pip install miepython scipy numpy

Creates 2 files:
  optical/coordination_optics_bridge.py       — Module 4a
  tests/test_optical/test_coordination_optics_bridge.py — 27 tests

Physics:
  Channel 1: Donor subtypes → spectrochemical Δ₀ → λ_dd → k(λ) (absorption)
  Channel 2: Metal + ligand polarizabilities → Δα → Lorentz-Lorenz → Δn (refractive index)

  Two stages per channel:
    Stage 1 (functionalization): anchored ligand replaces water on shell surface
    Stage 2 (metal coordination): metal ion displaces coordinated waters

  Shared data with binding engine: METAL_DB, DQ_BY_DONOR (same Python objects)

Validation (3 shells from META 2026 abstract Figure 2):
  BPMEN+Cu²⁺: Δ₀=16443 cm⁻¹, λ_dd=608nm, k>0, Δn=+0.012
  DTC+Pb²⁺:   Δ₀=0 (d¹⁰s²), k=0, Δn=+0.017 (largest — 6s² lone pair)
  Bipy+Cu²⁺:  Δ₀=17010 cm⁻¹, λ_dd=588nm, k>0, Δn=+0.015

  Rankings decoupled: Cu²⁺ strongest binder, Pb²⁺ strongest color shifter.
  Zero parameters fitted to structural color data.

Total: 27 new tests, all passing.
"""
import base64, pathlib

FILES = {
    "optical/coordination_optics_bridge.py": "",
    "tests/test_optical/test_coordination_optics_bridge.py": "",

}

def main():
    print()
    print("  MABE Module 4a — Coordination-Optics Bridge Bootstrap")
    print("  " + "=" * 54)
    print()
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64)
        p.write_bytes(content)
        print(f"  Created: {path} ({len(content):,} bytes)")
    print()
    print("  Run: python3 -m pytest tests/test_optical/test_coordination_optics_bridge.py -v")
    print()

if __name__ == "__main__":
    main()